/**
 * Public-facing snapshot of the download subsystem. Returned
 * by `GET /api/v1/playback/ffmpeg/download`; emitted via
 * `AppEvent` variants as the state transitions.
 */
export const zFfmpegDownloadState = z.union([
    z.object({
        status: z.enum(['idle'])
    }),
    z.object({
        bytes: z.coerce.bigint().gte(BigInt(0)).max(BigInt('9223372036854775807'), { error: 'Invalid value: Expected int64 to be <= 9223372036854775807' }),
        status: z.enum(['running']),
        total: z.coerce.bigint().gte(BigInt(0)).max(BigInt('9223372036854775807'), { error: 'Invalid value: Expected int64 to be <= 9223372036854775807' }),
        version: z.string()
    }),
    z.object({
        path: z.string(),
        status: z.enum(['completed']),
        version: z.string()
    }),
    z.object({
        reason: z.string(),
        status: z.enum(['failed'])
    })
]);

/**
 * Why a show sits in the library. Drives the self-cleanup
 * behaviour when its last acquired episode is discarded:
 * `Adhoc` shows auto-remove when empty, `Explicit` shows stick
 * around because the user deliberately followed them.
 *
 * Transitions:
 * - Follow dialog `create_show` → `Explicit`
 * - Auto-follow from Play / Get / acquire-by-tmdb → `Adhoc`
 * - Manage dialog `update_show_monitor` → flips `Adhoc` → `Explicit`
 * (submitting the dialog is commitment)
 */
export const zFollowIntent = z.enum(['explicit', 'adhoc']);

