/**
 * Entity kind for the unified play URL. Mirrors the `{kind}` path
 * segment in `/api/v1/play/{kind}/{entity_id}/...`. Lives here at the
 * domain root because it's a domain concept (every playback module
 * needs it: source resolution, HLS / direct handlers, the `watch_now`
 * orchestrator, the cast-token endpoint). Handlers used to own it,
 * which inverted the dependency direction.
 */
export const zPlayKind = z.enum(['movie', 'episode']);

/**
 * Response for `POST /api/v1/releases/{id}/grab-and-watch`. The
 * unified play identity: `{kind, entity_id}` — enough for the
 * client to navigate to `/play/{kind}/{entity_id}`. Whether the
 * byte source is the library or a still-in-progress torrent is
 * the dispatcher's concern, not the caller's.
 */
export const zGrabAndWatchReply = z.object({
    entity_id: z.coerce.bigint().min(BigInt('-9223372036854775808'), { error: 'Invalid value: Expected int64 to be >= -9223372036854775808' }).max(BigInt('9223372036854775807'), { error: 'Invalid value: Expected int64 to be <= 9223372036854775807' }),
    kind: zPlayKind
});

/**
 * Body for `POST /api/v1/play/{kind}/{entity_id}/progress`. Single
 * endpoint replaces `/playback/progress` (media-id) and
 * `/playback/stream/{id}/progress` (download-id). Backend writes
 * to the entity row (`movie.playback_position_ticks` /
 * `episode.playback_position_ticks`) directly — both source paths
 * resolve to the same row, so the write target is the same
 * regardless of whether the byte stream came from torrent or
 * library.
 */
export const zPlayProgressBody = z.object({
    final_tick: z.boolean().optional(),
    incognito: z.boolean().optional(),
    paused: z.boolean().optional(),
    position_secs: z.number()
});

/**
 * Unified state reported by `/prepare`. Mirrors the five user-
 * facing states the frontend chip + overlays discriminate on, plus
 * enough detail to drive them without a second round-trip.
 */
export const zPlayState = z.enum([
    'searching',
    'queued',
    'grabbing',
    'streaming',
    'paused',
    'failed',
    'downloaded'
]);

/**
 * How the server will serve this request.
 */
export const zPlaybackMethod = z.enum([
    'direct_play',
    'remux',
    'transcode'
]);

/**
 * Poll for token completion. Frontend calls this on the interval
 * given by [`begin_device`]. Returns one of:
 * - 200 with `{state: "pending"}` → keep polling
 * - 200 with `{state: "connected", username, slug}` → done
 * - 410 gone → user denied / code expired; restart flow
 */
export const zPollReply = z.union([
    z.object({
        state: z.enum(['pending'])
    }),
    z.object({
        slug: z.string(),
        state: z.enum(['connected']),
        username: z.string()
    }),
    z.object({
        reason: z.string(),
        state: z.enum(['invalid'])
    })
]);

export const zPollReq = z.object({
    device_code: z.string()
});

export const zQualityProfile = z.object({
    accepted_languages: z.string(),
    cutoff: z.string(),
    id: z.coerce.bigint().min(BigInt('-9223372036854775808'), { error: 'Invalid value: Expected int64 to be >= -9223372036854775808' }).max(BigInt('9223372036854775807'), { error: 'Invalid value: Expected int64 to be <= 9223372036854775807' }),
    is_default: z.boolean(),
    items: z.string(),
    name: z.string(),
    upgrade_allowed: z.boolean()
});

