/**
 * Per-season acquire + library stats. Drives the Manage-downloads
 * dialog's tri-state checkboxes: a season with every episode at
 * `acquire = 1` is "fully monitored" (checked), one with *some*
 * episodes acquired-or-imported is "partial" (indeterminate — e.g.
 * after streaming a single episode via Play), and one with neither
 * is "unmonitored" (unchecked).
 *
 * Kept as a dedicated endpoint rather than a column on the show row
 * because the data is derived — changing `episode.acquire` elsewhere
 * would otherwise require a mirror write.
 */
export const zSeasonAcquireState = z.object({
    acquiring: z.coerce.bigint().min(BigInt('-9223372036854775808'), { error: 'Invalid value: Expected int64 to be >= -9223372036854775808' }).max(BigInt('9223372036854775807'), { error: 'Invalid value: Expected int64 to be <= 9223372036854775807' }),
    in_library: z.coerce.bigint().min(BigInt('-9223372036854775808'), { error: 'Invalid value: Expected int64 to be >= -9223372036854775808' }).max(BigInt('9223372036854775807'), { error: 'Invalid value: Expected int64 to be <= 9223372036854775807' }),
    season_number: z.coerce.bigint().min(BigInt('-9223372036854775808'), { error: 'Invalid value: Expected int64 to be >= -9223372036854775808' }).max(BigInt('9223372036854775807'), { error: 'Invalid value: Expected int64 to be <= 9223372036854775807' }),
    total: z.coerce.bigint().min(BigInt('-9223372036854775808'), { error: 'Invalid value: Expected int64 to be >= -9223372036854775808' }).max(BigInt('9223372036854775807'), { error: 'Invalid value: Expected int64 to be <= 9223372036854775807' })
});

