/**
 * Show plus per-show rollups used by the library list. Exists so
 * the Library page's Wanted tab can show TV rows without needing a
 * second round-trip per show — the counts are cheap correlated
 * subqueries bundled into the list query.
 *
 * `FromRow` is implemented by hand so `next_episode` / `active_download`
 * (which aren't selected from the main list-shows SQL — they're
 * attached in a second pass) don't trip sqlx's "no `Decode` impl for
 * struct" check that `#[sqlx(default)]` can't silence.
 */
export const zShowListItem = zShow.and(z.object({
    active_download: zActiveShowDownload.nullish(),
    aired_episode_count: z.coerce.bigint().min(BigInt('-9223372036854775808'), { error: 'Invalid value: Expected int64 to be >= -9223372036854775808' }).max(BigInt('9223372036854775807'), { error: 'Invalid value: Expected int64 to be <= 9223372036854775807' }),
    available_episode_count: z.coerce.bigint().min(BigInt('-9223372036854775808'), { error: 'Invalid value: Expected int64 to be >= -9223372036854775808' }).max(BigInt('9223372036854775807'), { error: 'Invalid value: Expected int64 to be <= 9223372036854775807' }),
    episode_count: z.coerce.bigint().min(BigInt('-9223372036854775808'), { error: 'Invalid value: Expected int64 to be >= -9223372036854775808' }).max(BigInt('9223372036854775807'), { error: 'Invalid value: Expected int64 to be <= 9223372036854775807' }),
    next_episode: zNextEpisode.nullish(),
    upcoming_episode_count: z.coerce.bigint().min(BigInt('-9223372036854775808'), { error: 'Invalid value: Expected int64 to be >= -9223372036854775808' }).max(BigInt('9223372036854775807'), { error: 'Invalid value: Expected int64 to be <= 9223372036854775807' }),
    wanted_episode_count: z.coerce.bigint().min(BigInt('-9223372036854775808'), { error: 'Invalid value: Expected int64 to be >= -9223372036854775808' }).max(BigInt('9223372036854775807'), { error: 'Invalid value: Expected int64 to be <= 9223372036854775807' }),
    watched_episode_count: z.coerce.bigint().min(BigInt('-9223372036854775808'), { error: 'Invalid value: Expected int64 to be >= -9223372036854775808' }).max(BigInt('9223372036854775807'), { error: 'Invalid value: Expected int64 to be <= 9223372036854775807' })
}));

