/**
 * Latest encoder-progress snapshot parsed from the `-progress pipe:2`
 * key=value block ffmpeg emits once a second. Driven by the player
 * chip so the user can see encoder throughput in real time — a
 * `speed` of `< 1.0` is a reliable early warning that HLS playback
 * will stall.
 */
export const zTranscodeProgress = z.object({
    bitrate_kbps: z.number().nullish(),
    speed: z.number(),
    time_secs: z.number()
});

/**
 * A single reason the playback layer had to diverge from direct
 * play. Flags combine into `TranscodeReasons` — see that type for
 * the set-level API.
 *
 * Variant order is stable: new variants append. The `as_str` /
 * `from_str` mapping is the wire contract — changing a name is
 * a breaking change.
 */
export const zTranscodeReason = z.enum([
    'container_not_supported',
    'video_codec_not_supported',
    'video_profile_not_supported',
    'video_level_not_supported',
    'video_bit_depth_not_supported',
    'video_range_type_not_supported',
    'video_resolution_not_supported',
    'video_framerate_not_supported',
    'video_bitrate_not_supported',
    'audio_codec_not_supported',
    'audio_channels_not_supported',
    'audio_sample_rate_not_supported',
    'audio_bit_depth_not_supported',
    'audio_bitrate_not_supported',
    'subtitle_codec_not_supported'
]);

/**
 * Set of reasons. Ordered (`BTreeSet`) so serialization is
 * deterministic and logs diff cleanly.
 *
 * Wire format is `Vec<TranscodeReason>` — serde flattens via
 * `#[serde(transparent)]`, and utoipa generates a
 * `Array<TranscodeReason>` schema so the frontend sees a plain
 * `TranscodeReason[]`.
 */
export const zTranscodeReasons = z.array(zTranscodeReason);

/**
 * The engine's verdict on a request. `transcode_reasons` is
 * `empty()` iff `method == DirectPlay`.
 */
export const zPlaybackPlan = z.object({
    audio_passthrough: z.boolean().optional(),
    method: zPlaybackMethod,
    selected_audio_stream: z.coerce.bigint().min(BigInt('-9223372036854775808'), { error: 'Invalid value: Expected int64 to be >= -9223372036854775808' }).max(BigInt('9223372036854775807'), { error: 'Invalid value: Expected int64 to be <= 9223372036854775807' }).nullish(),
    transcode_reasons: zTranscodeReasons,
    video_bitstream_filter: z.string().nullish()
});

